#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_BUSHES 10000
#define MAX_RELATIONS 3

// Structure to represent a bush
typedef struct {
    int index;
    int relations[MAX_RELATIONS];
    int num_relations;
} Bush;

// Function to read input and initialize the graph
void read_input(Bush *bushes, int *n, int *s, int *t, int **saved_bushes) {
    // Read the number of test cases
    int T;
    scanf("%d", &T);

    for (int i = 0; i < T; i++) {
        // Read the number of bushes, the initially burning bush, and the number of bushes to save
        scanf("%d %d %d", n, s, t);

        // Initialize the graph
        for (int j = 0; j < *n; j++) {
            // Read the number of relations for the current bush
            int num_relations;
            scanf("%d", &num_relations);
            bushes[j].num_relations = num_relations;

            // Read the relations for the current bush
            for (int k = 0; k < num_relations; k++) {
                scanf("%d", &bushes[j].relations[k]);
            }
        }

        // Read the indices of the bushes to save
        *saved_bushes = (int *) malloc((*t) * sizeof(int));
        for (int j = 0; j < *t; j++) {
            scanf("%d", &(*saved_bushes)[j]);
        }
    }
}

// Function to simulate the spread of the fire and check if it is possible to save all the required bushes
void simulate_fire(Bush *bushes, int n, int s, int t, int *saved_bushes) {
    // Initialize a queue with the initially burning bush
    int queue[n];
    int front = 0, rear = 0;
    queue[rear++] = s - 1;

    // Initialize a set to keep track of the saved bushes
    int saved[n];
    memset(saved, 0, n * sizeof(int));

    // Initialize a set to keep track of the burned bushes
    int burned[n];
    memset(burned, 0, n * sizeof(int));

    while (front < rear) {
        // Dequeue the next bush
        int current_bush = queue[front++];

        // If the current bush is already burned, skip it
        if (burned[current_bush]) {
            continue;
        }

        // Mark the current bush as burned
        burned[current_bush] = 1;

        // Check if the current bush is one of the bushes to save
        for (int i = 0; i < t; i++) {
            if (saved_bushes[i] - 1 == current_bush) {
                // If the current bush is already burned, it is not possible to save it
                printf("no\n");
                return;
            }
        }

        // Enqueue the neighbors of the current bush
        for (int i = 0; i < bushes[current_bush].num_relations; i++) {
            int neighbor = bushes[current_bush].relations[i] - 1;

            // If the neighbor is not already burned, enqueue it
            if (!burned[neighbor]) {
                queue[rear++] = neighbor;
            }
        }
    }

    // If all the required bushes are saved, print 'yes'
    printf("yes\n");
}

int main() {
    int T;
    scanf("%d", &T);

    for (int i = 0; i < T; i++) {
        int n, s, t;
        int *saved_bushes;
        Bush bushes[MAX_BUSHES];
        read_input(bushes, &n, &s, &t, &saved_bushes);
        simulate_fire(bushes, n, s, t, saved_bushes);
        free(saved_bushes);
    }

    return 0;
}

